// Calcula startDateTime y endDateTime en zona horaria Europe/Madrid
// según el rango recibido: today | tomorrow | week

const { DateTime } = require('luxon');
const tz = 'Europe/Madrid';
const ahora = DateTime.now().setZone(tz);
const rango = $input.first().json.range;

let startDateTime, endDateTime, humanRangeLabel;

if (rango === 'today') {
  startDateTime = ahora.startOf('day');
  endDateTime   = ahora.endOf('day');
  humanRangeLabel = 'hoy';

} else if (rango === 'tomorrow') {
  const manana = ahora.plus({ days: 1 });
  startDateTime = manana.startOf('day');
  endDateTime   = manana.endOf('day');
  humanRangeLabel = 'mañana';

} else if (rango === 'week') {
  // Lunes 00:00 → domingo 23:59:59 de la semana en curso
  // Luxon usa lunes como inicio de semana ISO (semana estándar europea)
  startDateTime = ahora.startOf('week');
  endDateTime   = ahora.endOf('week');
  humanRangeLabel = 'esta semana';

} else {
  throw new Error(`Rango no válido: "${rango}". Valores aceptados: today | tomorrow | week`);
}

return [{
  json: {
    range: rango,
    startDateTime: startDateTime.toISO(),
    endDateTime:   endDateTime.toISO(),
    timezone: tz,
    humanRangeLabel
  }
}];

// Convierte los eventos de Google Calendar en texto legible
// Formato: 'Tienes N eventos hoy:\n\n• HH:MM–HH:MM Título'

const { DateTime } = require('luxon');
const tz = 'Europe/Madrid';

// Leer humanRangeLabel calculado en el nodo anterior
const humanRangeLabel = $('Calcular rango de fechas').first().json.humanRangeLabel;

// Filtrar solo ítems con id (eventos reales, no ítems vacíos de n8n)
const eventos = $input.all().filter(item => item.json && item.json.id);

if (eventos.length === 0) {
  return [{ json: { text: `No tienes nada en la agenda de ${humanRangeLabel}.` } }];
}

const lineas = eventos.map(item => {
  const ev = item.json;
  const titulo = ev.summary || '(sin título)';

  // Evento de todo el día: tiene start.date pero no start.dateTime
  if (ev.start?.date && !ev.start?.dateTime) {
    return `• Todo el día — ${titulo}`;
  }

  const inicio = DateTime.fromISO(ev.start.dateTime).setZone(tz).toFormat('HH:mm');
  const fin    = DateTime.fromISO(ev.end.dateTime).setZone(tz).toFormat('HH:mm');
  return `• ${inicio}–${fin} ${titulo}`;
});

const n = eventos.length;
const cabecera = `Tienes ${n} evento${n !== 1 ? 's' : ''} ${humanRangeLabel}:`;
const texto = `${cabecera}\n\n${lineas.join('\n')}`;

return [{ json: { text: texto } }];
